import type { Config } from "tailwindcss";

const config: Config = {
  content: [
    "./pages/**/*.{js,ts,jsx,tsx,mdx}",
    "./components/**/*.{js,ts,jsx,tsx,mdx}",
    "./app/**/*.{js,ts,jsx,tsx,mdx}",
  ],
  theme: {
    extend: {
      colors: {
        charcoal: "#2C2C2C",
        ivory: "#F5F0E8",
        gold: "#C5A55A",
        burgundy: "#8C3A3A",
        ivoryDark: "#EDE8DC",
        goldLight: "#D4BC91",
        charcoalLight: "#3D3D3D",
      },
      fontFamily: {
        heading: [
          "Outfit",
          "Georgia",
          "Cambria",
          '"Times New Roman"',
          "Times",
          "serif",
        ],
        body: [
          '"Plus Jakarta Sans"',
          '"Helvetica Neue"',
          "Helvetica",
          "Arial",
          "sans-serif",
        ],
      },
      fontSize: {
        "hero": ["5rem", { lineHeight: "1.05", letterSpacing: "-0.02em" }],
        "section-title": ["3rem", { lineHeight: "1.1", letterSpacing: "-0.01em" }],
        "subsection": ["1.5rem", { lineHeight: "1.3" }],
      },
      animation: {
        "fade-in": "fadeIn 0.8s ease-out forwards",
        "slide-up": "slideUp 0.8s ease-out forwards",
        "pulse-gold": "pulseGold 2s ease-in-out infinite",
      },
      keyframes: {
        fadeIn: {
          "0%": { opacity: "0" },
          "100%": { opacity: "1" },
        },
        slideUp: {
          "0%": { opacity: "0", transform: "translateY(30px)" },
          "100%": { opacity: "1", transform: "translateY(0)" },
        },
        pulseGold: {
          "0%, 100%": { boxShadow: "0 0 0 0 rgba(197,165,114,0.4)" },
          "50%": { boxShadow: "0 0 0 12px rgba(197,165,114,0)" },
        },
      },
    },
  },
  plugins: [],
};

export default config;

import type { Metadata } from "next";
import "./globals.css";
import Providers from "@/components/Providers";
import Navbar from "@/components/Navbar";

export const metadata: Metadata = {
  title: "NearBy — Buy and Sell with Neighbors You Can Trust",
  description:
    "A neighborhood marketplace built on real trust and verification. Buy and sell with the people who actually live around you.",
};

export default function RootLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <html lang="en">
      <body className="min-h-screen bg-ivory text-charcoal antialiased">
        <Providers>
          <Navbar />
          {children}
        </Providers>
      </body>
    </html>
  );
}

import Hero from "@/components/Hero";
import WhatWereBuilding from "@/components/WhatWereBuilding";
import Waitlist from "@/components/Waitlist";
import HowItWorks from "@/components/HowItWorks";
import FAQ from "@/components/FAQ";

export default function Home() {
  return (
    <main>
      <Hero />
      <WhatWereBuilding />
      <Waitlist />
      <HowItWorks />
      <FAQ />

      {/* Footer */}
      <footer className="py-12 px-6 bg-ivory border-t border-charcoal/5">
        <div className="max-w-5xl mx-auto flex flex-col md:flex-row items-center justify-between gap-4">
          <div className="heading-serif text-xl text-charcoal">
            NearBy
          </div>
          <p className="text-[11px] text-charcoal/40 font-light tracking-wide">
            &copy; {new Date().getFullYear()} NearBy. All rights reserved.
          </p>
        </div>
      </footer>
    </main>
  );
}

@tailwind base;
@tailwind components;
@tailwind utilities;

@import url("https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700&family=Plus+Jakarta+Sans:ital,wght@0,300;0,400;0,500;0,600;0,700;1,400;1,500&display=swap");

@layer base {
  html {
    scroll-behavior: smooth;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
  }

  body {
    background-color: #f5f0e8;
    color: #2c2c2c;
    font-family: "Plus Jakarta Sans", "Helvetica Neue", Helvetica, Arial, sans-serif;
  }

  ::selection {
    background-color: #c5a572;
    color: #2c2c2c;
  }
}

@layer components {
  .heading-serif {
    font-family: "Outfit", Georgia, Cambria, "Times New Roman",
      Times, serif;
    font-weight: 500;
  }

  .section-divider {
    width: 60px;
    height: 2px;
    background-color: #c5a572;
  }

  .card-surface {
    background-color: #ffffff;
    border: 1px solid rgba(197, 165, 114, 0.15);
    box-shadow: 0 2px 20px rgba(44, 44, 44, 0.04);
  }

  .card-surface-hover:hover {
    box-shadow: 0 8px 32px rgba(44, 44, 44, 0.08);
    border-color: rgba(197, 165, 114, 0.3);
  }

  .gold-gradient {
    background: linear-gradient(135deg, #c5a572 0%, #d4bc91 50%, #c5a572 100%);
  }

  .input-luxury {
    background-color: #ffffff;
    border: 1px solid rgba(197, 165, 114, 0.3);
    transition: all 0.3s ease;
  }

  .input-luxury:focus {
    border-color: #c5a572;
    box-shadow: 0 0 0 3px rgba(197, 165, 114, 0.15);
    outline: none;
  }
}

@layer utilities {
  .text-balance {
    text-wrap: balance;
  }
}

/* Subtle scroll reveal animation */
.reveal {
  opacity: 0;
  transform: translateY(24px);
  transition: opacity 0.7s ease, transform 0.7s ease;
}

.reveal.visible {
  opacity: 1;
  transform: translateY(0);
}

"use client";

export default function Hero() {
  return (
    <section className="relative min-h-screen flex items-center justify-center overflow-hidden">
      {/* Background texture */}
      <div className="absolute inset-0 opacity-[0.03]" style={{
        backgroundImage: `url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%232C2C2C' fill-opacity='1'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E")`,
      }} />

      {/* Decorative top gold line */}
      <div className="absolute top-0 left-0 right-0 h-[1px] bg-gradient-to-r from-transparent via-gold to-transparent" />

      {/* Main content */}
      <div className="relative z-10 max-w-4xl mx-auto px-6 text-center">
        {/* Badge */}
        <div className="inline-flex items-center gap-2 mb-8">
          <span className="inline-block px-4 py-1.5 text-[11px] font-medium tracking-[0.2em] uppercase text-gold border border-gold/30 rounded-full">
            Coming Soon
          </span>
        </div>

        {/* Company name */}
        <h1 className="heading-serif text-hero text-charcoal mb-6 animate-fade-in">
          NearBy
        </h1>

        {/* Tagline */}
        <p className="heading-serif text-section-title text-charcoalLight mb-8 animate-slide-up text-balance">
          Buy and Sell with Neighbors
          <br />
          <span className="text-gold italic">You Can Trust</span>
        </p>

        {/* Value proposition */}
        <p className="max-w-xl mx-auto text-base leading-relaxed text-charcoal/70 mb-12 animate-slide-up font-light">
          NearBy is a neighborhood marketplace built on real verification and
          genuine community trust. List your items, find what you need, and
          transact with people who actually live around you — no strangers, no
          guesswork, no anxiety.
        </p>

        {/* Single CTA — waitlist */}
        <a
          href="#waitlist"
          className="inline-flex items-center gap-2 px-8 py-3.5 bg-charcoal text-ivory text-sm font-medium tracking-wide rounded-full transition-all duration-300 hover:bg-charcoalLight hover:shadow-lg hover:shadow-charcoal/10 hover:-translate-y-0.5"
        >
          Join the Waitlist
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none" className="ml-1">
            <path d="M3 8h10M9 4l4 4-4 4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
        </a>

        {/* Scroll indicator */}
        <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex flex-col items-center gap-2 opacity-40">
          <span className="text-[10px] tracking-[0.15em] uppercase text-charcoal">Scroll</span>
          <div className="w-[1px] h-8 bg-charcoal/30 relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-1/2 bg-gold animate-pulse" />
          </div>
        </div>
      </div>
    </section>
  );
}

import Link from 'next/link';
import { auth } from '@/lib/auth';
import NavbarClient from './NavbarClient';

export default async function Navbar() {
  const session = await auth();
  return <NavbarClient session={session} />;
}

"use client";

import { useState, FormEvent } from "react";

export default function Waitlist() {
  const [email, setEmail] = useState("");
  const [status, setStatus] = useState<"idle" | "submitting" | "success" | "error">("idle");
  const [errorMsg, setErrorMsg] = useState("");

  async function handleSubmit(e: FormEvent) {
    e.preventDefault();
    if (!email) return;

    setStatus("submitting");
    setErrorMsg("");

    try {
      const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
      const supabaseKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;

      // If Supabase is not configured, use local storage fallback for demo
      if (!supabaseUrl || !supabaseKey || supabaseUrl.includes("placeholder")) {
        // Store in localStorage as fallback
        const existing = JSON.parse(localStorage.getItem("nearby_waitlist") || "[]");
        if (!existing.includes(email)) {
          existing.push(email);
          localStorage.setItem("nearby_waitlist", JSON.stringify(existing));
        }
        setStatus("success");
        setEmail("");
        return;
      }

      const res = await fetch(`${supabaseUrl}/rest/v1/waitlist`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          apikey: supabaseKey,
          Authorization: `Bearer ${supabaseKey}`,
          Prefer: "return=representation",
        },
        body: JSON.stringify({ email }),
      });

      if (res.ok) {
        setStatus("success");
        setEmail("");
      } else {
        const data = await res.json();
        if (data.code === "23505") {
          setStatus("success");
          setEmail("");
        } else {
          setErrorMsg(data.message || "Something went wrong. Please try again.");
          setStatus("error");
        }
      }
    } catch {
      setErrorMsg("Network error. Please try again.");
      setStatus("error");
    }
  }

  return (
    <section id="waitlist" className="py-24 px-6 bg-charcoal text-ivory relative overflow-hidden">
      {/* Background pattern */}
      <div className="absolute inset-0 opacity-[0.04]" style={{
        backgroundImage: `url("data:image/svg+xml,%3Csvg width='40' height='40' viewBox='0 0 40 40' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='%23F5F0E8' fill-opacity='1' fill-rule='evenodd'%3E%3Cpath d='M0 40L40 0H20L0 20M40 40V20L20 40'/%3E%3C/g%3E%3C/svg%3E")`,
      }} />

      <div className="relative z-10 max-w-2xl mx-auto text-center">
        {/* Section header */}
        <span className="text-[11px] font-medium tracking-[0.2em] uppercase text-gold mb-4 block">
          Join the Waitlist
        </span>
        <h2 className="heading-serif text-section-title text-ivory text-balance mb-4">
          Be First in Your Neighborhood
        </h2>
        <p className="text-sm leading-relaxed text-ivory/60 mb-10 max-w-md mx-auto font-light">
          Sign up to get notified the moment NearBy launches in your area. Early
          members get priority access and help shape the platform.
        </p>

        {/* Form */}
        {status === "success" ? (
          <div className="p-8 rounded-2xl bg-charcoalLight border border-gold/20">
            <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-gold/10 mb-4">
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#C5A572" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <polyline points="20 6 9 17 4 12" />
              </svg>
            </div>
            <h3 className="heading-serif text-xl text-ivory mb-2">
              You're on the list
            </h3>
            <p className="text-sm text-ivory/50 font-light">
              We'll notify you as soon as NearBy is ready. Keep an eye on your inbox.
            </p>
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="flex flex-col sm:flex-row gap-3 max-w-lg mx-auto">
            <div className="flex-1 relative">
              <input
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="your@email.com"
                className="w-full px-5 py-3.5 rounded-full bg-charcoalLight border border-ivory/10 text-ivory text-sm placeholder:text-ivory/30 focus:outline-none focus:border-gold/40 focus:ring-1 focus:ring-gold/20 transition-all"
                disabled={status === "submitting"}
              />
            </div>
            <button
              type="submit"
              disabled={status === "submitting"}
              className="px-7 py-3.5 rounded-full gold-gradient text-charcoal text-sm font-medium tracking-wide transition-all duration-300 hover:shadow-lg hover:shadow-gold/20 hover:-translate-y-0.5 disabled:opacity-60 disabled:cursor-not-allowed whitespace-nowrap"
            >
              {status === "submitting" ? (
                <span className="inline-flex items-center gap-2">
                  <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
                  </svg>
                  Joining...
                </span>
              ) : (
                "Join the Waitlist"
              )}
            </button>
          </form>
        )}

        {/* Error message */}
        {status === "error" && errorMsg && (
          <p className="mt-4 text-sm text-burgundy font-light">{errorMsg}</p>
        )}

        {/* Privacy note */}
        <p className="mt-6 text-[11px] text-ivory/30 font-light">
          We respect your inbox. No spam — just a single email when we launch.
        </p>
      </div>
    </section>
  );
}

"use client";

const steps = [
  {
    number: "01",
    title: "ID Check",
    description:
      "Verify your identity with a quick government ID check. We confirm you're a real person — no bots, no fake accounts.",
    icon: (
      <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
        <rect x="2" y="5" width="20" height="14" rx="2" />
        <line x1="2" y1="10" x2="22" y2="10" />
      </svg>
    ),
  },
  {
    number: "02",
    title: "Address Verification",
    description:
      "Confirm your home address and we'll verify you belong to a real neighborhood. This ensures every member is an actual resident.",
    icon: (
      <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
        <path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z" />
        <circle cx="12" cy="10" r="3" />
      </svg>
    ),
  },
  {
    number: "03",
    title: "Neighborhood Badge",
    description:
      "Once verified, you receive your Neighborhood Badge — a visible trust marker that shows neighbors you're the real deal.",
    icon: (
      <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
        <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z" />
        <polyline points="9 12 11 14 15 10" />
      </svg>
    ),
  },
];

export default function HowItWorks() {
  return (
    <section className="py-24 px-6 bg-white">
      <div className="max-w-5xl mx-auto">
        {/* Section header */}
        <div className="text-center mb-16">
          <span className="text-[11px] font-medium tracking-[0.2em] uppercase text-gold mb-4 block">
            How It Works
          </span>
          <h2 className="heading-serif text-section-title text-charcoal text-balance">
            Three Steps to Trustworthy Commerce
          </h2>
          <div className="section-divider mx-auto mt-6" />
        </div>

        {/* Steps grid */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 md:gap-12">
          {steps.map((step) => (
            <div key={step.number} className="relative group">
              {/* Connector line (desktop only) */}
              {step.number !== "03" && (
                <div className="hidden md:block absolute top-14 left-[calc(50%+40px)] right-[calc(-50%+40px)] h-[1px] bg-gold/20" />
              )}

              <div className="text-center px-4">
                {/* Icon circle */}
                <div className="relative inline-flex items-center justify-center w-[72px] h-[72px] rounded-full border border-gold/20 bg-ivory mb-6 group-hover:border-gold/50 transition-colors duration-300">
                  <span className="text-gold">{step.icon}</span>
                  {/* Step number overlay */}
                  <span className="absolute -top-1 -right-1 w-6 h-6 rounded-full bg-charcoal text-ivory text-[10px] font-medium flex items-center justify-center">
                    {step.number}
                  </span>
                </div>

                <h3 className="heading-serif text-subsection text-charcoal mb-3">
                  {step.title}
                </h3>
                <p className="text-sm leading-relaxed text-charcoal/60 max-w-[280px] mx-auto font-light">
                  {step.description}
                </p>
              </div>
            </div>
          ))}
        </div>

        {/* Trust verification callout */}
        <div className="mt-16 p-6 md:p-8 rounded-2xl bg-ivory border border-gold/10 text-center max-w-2xl mx-auto">
          <div className="inline-flex items-center gap-2 mb-3">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#C5A572" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z" />
            </svg>
            <span className="text-[11px] font-medium tracking-[0.15em] uppercase text-gold">
              Trust Verification
            </span>
          </div>
          <p className="text-sm leading-relaxed text-charcoal/70 font-light">
            Our three-step verification ensures every NearBy member is a verified
            resident with a real stake in their community. No anonymous strangers
            — just neighbors you can trust.
          </p>
        </div>
      </div>
    </section>
  );
}

"use client";

import { useState } from "react";

const faqs = [
  {
    question: "When will NearBy launch?",
    answer:
      "We're in active development and plan to launch in select neighborhoods first. Join the waitlist to be notified the moment your area is added. We're prioritizing communities where demand is strongest.",
  },
  {
    question: "How is NearBy different from Facebook Marketplace or Craigslist?",
    answer:
      "Facebook Marketplace and Craigslist connect you with anyone — often strangers you'll never see again. NearBy is restricted to verified residents of your actual neighborhood. Every member has confirmed their home address, creating a layer of accountability that anonymous platforms simply cannot offer.",
  },
  {
    question: "Is my address kept private?",
    answer:
      "Yes. Your exact address is never shown to other users. We verify it behind the scenes to confirm you belong to a neighborhood, but your listing shows only your general area — not your front door.",
  },
  {
    question: "What does it cost to use NearBy?",
    answer:
      "NearBy will be free for basic buying and selling. We may introduce optional premium features in the future, but the core marketplace — listing items, browsing, messaging neighbors — will always be free.",
  },
];

export default function FAQ() {
  const [openIndex, setOpenIndex] = useState<number | null>(null);

  return (
    <section className="py-24 px-6 bg-white">
      <div className="max-w-2xl mx-auto">
        {/* Section header */}
        <div className="text-center mb-14">
          <span className="text-[11px] font-medium tracking-[0.2em] uppercase text-gold mb-4 block">
            FAQ
          </span>
          <h2 className="heading-serif text-section-title text-charcoal">
            Honest Answers
          </h2>
          <div className="section-divider mx-auto mt-6" />
        </div>

        {/* FAQ items */}
        <div className="space-y-0">
          {faqs.map((faq, index) => (
            <div
              key={index}
              className="border-b border-charcoal/10 last:border-b-0"
            >
              <button
                onClick={() => setOpenIndex(openIndex === index ? null : index)}
                className="w-full flex items-center justify-between py-5 text-left group"
                aria-expanded={openIndex === index}
              >
                <span className="heading-serif text-lg text-charcoal group-hover:text-gold transition-colors duration-200 pr-4">
                  {faq.question}
                </span>
                <span className="flex-shrink-0 w-8 h-8 rounded-full border border-charcoal/10 flex items-center justify-center group-hover:border-gold/30 transition-colors duration-200">
                  <svg
                    width="14"
                    height="14"
                    viewBox="0 0 14 14"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="1.5"
                    strokeLinecap="round"
                    className={`text-charcoal/40 transition-transform duration-300 ${
                      openIndex === index ? "rotate-45" : ""
                    }`}
                  >
                    <line x1="7" y1="1" x2="7" y2="13" />
                    <line x1="1" y1="7" x2="13" y2="7" />
                  </svg>
                </span>
              </button>
              <div
                className={`overflow-hidden transition-all duration-400 ease-in-out ${
                  openIndex === index ? "max-h-48 pb-5" : "max-h-0"
                }`}
              >
                <p className="text-sm leading-relaxed text-charcoal/55 font-light pr-12">
                  {faq.answer}
                </p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

"use client";

const benefits = [
  {
    title: "Verified Neighbors",
    description:
      "Every member confirms their real identity and home address. No anonymous accounts, no catfishing — just people who actually live in your neighborhood.",
    icon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
        <path d="M16 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2" />
        <circle cx="8.5" cy="7" r="4" />
        <polyline points="17 11 19 13 23 9" />
      </svg>
    ),
  },
  {
    title: "Hyperlocal Radius",
    description:
      "Your listings are only visible within your neighborhood boundaries. Browse and sell to people within walking distance — no long drives, no shipping hassles.",
    icon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
        <path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z" />
        <circle cx="12" cy="10" r="3" />
      </svg>
    ),
  },
  {
    title: "Safe Meetups",
    description:
      "Meet at familiar neighborhood spots — the local café, the park, the community center. Suggested pickup locations are landmarks you both know and trust.",
    icon: (
