  createdAt: number;
}

export type ListingStatus = 'active' | 'sold' | 'removed';

export interface Listing {
  id: string;
  sellerId: string;
  title: string;
  description: string;
  price: number;
  category: CategorySlug;
  neighborhood: string;
  photoUrl: string | null;
  status: ListingStatus;
  flagged: boolean;
  flagReason?: string;
  createdAt: number;
}

export interface Thread {
  id: string;
  listingId: string;
  buyerId: string;
  sellerId: string;
  lastMessageAt: number;
  createdAt: number;
}

export interface Message {
  id: string;
  threadId: string;
  senderId: string;
  body: string;
  createdAt: number;
}

export interface Review {
  id: string;
  reviewerId: string;
  revieweeId: string;
  listingId?: string;
  rating: 1 | 2 | 3 | 4 | 5;
  body: string;
  createdAt: number;
}

import { DefaultSession } from 'next-auth';

declare module 'next-auth' {
  interface Session {
    user: {
      id: string;
      role: string;
      neighborhood: string;
    } & DefaultSession['user'];
  }
}

declare module 'next-auth/jwt' {
  interface JWT {
    id: string;
    role: string;
    neighborhood: string;
  }
}

'use client';

import { Suspense, useState } from 'react';
import { signIn } from 'next-auth/react';
import { useRouter, useSearchParams } from 'next/navigation';
import Link from 'next/link';

export default function LoginPage() {
  return (
    <Suspense>
      <LoginForm />
    </Suspense>
  );
}

function LoginForm() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const returnTo = searchParams.get('return') || '/dashboard';
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  async function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    setError('');
    setLoading(true);
    const formData = new FormData(e.currentTarget);
    const email = formData.get('email') as string;
    const password = formData.get('password') as string;

    const res = await signIn('credentials', { email, password, redirect: false });
    setLoading(false);
    if (res?.error) {
      setError('Invalid email or password.');
    } else {
      router.push(returnTo);
      router.refresh();
    }
  }

  return (
    <div className="min-h-screen flex">
      <div className="hidden lg:flex lg:w-1/2 bg-charcoal items-center justify-center p-12">
        <div className="max-w-sm text-center">
          <Link href="/" className="heading-serif text-4xl text-ivory block mb-6">NearBy</Link>
          <p className="text-ivory/60 text-sm leading-relaxed">
            Trade with neighbors you can trust. Your block has more than you think.
          </p>
        </div>
      </div>
      <div className="w-full lg:w-1/2 bg-ivory flex items-center justify-center p-8">
        <div className="w-full max-w-sm">
          <Link href="/" className="heading-serif text-2xl text-charcoal block mb-8 lg:hidden">NearBy</Link>
          <h1 className="heading-serif text-3xl text-charcoal mb-2">Welcome back.</h1>
          <p className="text-stone text-sm mb-8">Sign in to your NearBy account.</p>
          {error && (
            <div className="mb-4 px-4 py-3 border border-burgundy/30 bg-burgundy/5 text-burgundy text-sm rounded-sm">
              {error}
            </div>
          )}
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-xs uppercase tracking-wider text-stone mb-1.5">Email</label>
              <input
                name="email"
                type="email"
                required
                className="w-full px-4 py-3 bg-cream border border-mist rounded-sm text-charcoal text-sm focus:border-gold focus:ring-1 focus:ring-gold/20 outline-none transition-colors"
                placeholder="you@example.com"
              />
            </div>
            <div>
              <label className="block text-xs uppercase tracking-wider text-stone mb-1.5">Password</label>
              <input
                name="password"
                type="password"
                required
                className="w-full px-4 py-3 bg-cream border border-mist rounded-sm text-charcoal text-sm focus:border-gold focus:ring-1 focus:ring-gold/20 outline-none transition-colors"
                placeholder="Your password"
              />
            </div>
            <button
              type="submit"
              disabled={loading}
              className="w-full py-3 bg-gold text-white text-sm font-medium rounded-sm transition-colors duration-150 hover:bg-gold/90 disabled:opacity-50"
            >
              {loading ? 'Signing in...' : 'Sign in'}
            </button>
          </form>
          <p className="mt-6 text-center text-sm text-stone">
            New here?{' '}
            <Link href="/signup" className="text-gold hover:text-gold/80 transition-colors">
              Create an account
            </Link>
          </p>
          <p className="mt-3 text-center text-xs text-stone/60">
            Demo: demo@demo.app / demo123
          </p>
        </div>
      </div>
    </div>
  );
}

import { auth } from '@/lib/auth';
import { redirect } from 'next/navigation';
import Link from 'next/link';
import { store } from '@/lib/store';

export default async function DashboardPage() {
  const session = await auth();
  if (!session?.user?.id) redirect('/login?return=/dashboard');

  const user = store.findById(session.user.id);
  const userListings = store.getUserListings(session.user.id);
  const activeListings = userListings.filter((l) => l.status === 'active');
  const soldListings = userListings.filter((l) => l.status === 'sold');
  const threads = store.getThreadsForUser(session.user.id);
  const reviews = store.getReviewsForUser(session.user.id);
  const trustScore = store.computeTrustScore(session.user.id);

  return (
    <main className="max-w-5xl mx-auto px-6 py-12">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="heading-serif text-section-title text-charcoal">Dashboard</h1>
          <p className="text-charcoal/50 mt-1">Welcome back, {user?.name ?? 'there'}</p>
        </div>
        <Link
          href="/sell"
          className="gold-gradient text-charcoal text-sm font-medium px-6 py-2.5 rounded-sm hover:opacity-90 transition-opacity"
        >
          + New listing
        </Link>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-12">
        {[
          { label: 'Active listings', value: activeListings.length },
          { label: 'Sold', value: soldListings.length },
          { label: 'Conversations', value: threads.length },
          { label: 'Trust score', value: `${trustScore}/5.0` },
        ].map((stat) => (
          <div key={stat.label} className="card-surface rounded-sm p-5 text-center">
            <p className="text-2xl font-heading text-charcoal">{stat.value}</p>
            <p className="text-xs text-charcoal/40 mt-1 uppercase tracking-wider">{stat.label}</p>
          </div>
        ))}
      </div>

      {/* Your listings */}
      <section className="mb-12">
        <div className="flex items-center justify-between mb-4">
          <h2 className="heading-serif text-subsection text-charcoal">Your listings</h2>
          <Link href="/browse" className="text-xs text-gold hover:text-goldLight transition-colors">Browse all</Link>
        </div>
        {activeListings.length === 0 ? (
          <div className="card-surface rounded-sm p-8 text-center">
            <p className="text-charcoal/40 mb-3">No active listings yet</p>
            <Link href="/sell" className="text-gold text-sm hover:text-goldLight transition-colors">List your first item</Link>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {activeListings.map((l) => (
              <Link key={l.id} href={`/items/${l.id}`} className="card-surface card-surface-hover rounded-sm p-4 block transition-all duration-150">
                <h3 className="font-heading text-charcoal leading-snug mb-1">{l.title}</h3>
                <p className="text-gold font-heading text-lg">${l.price}</p>
                <div className="flex items-center gap-2 text-xs text-charcoal/40 mt-2">
                  <span className="px-2 py-0.5 bg-ivoryDark rounded-sm capitalize">{l.category}</span>
                  <span>{l.neighborhood}</span>
                </div>
              </Link>
            ))}
          </div>
        )}
      </section>

      {/* Recent messages */}
      <section>
        <div className="flex items-center justify-between mb-4">
          <h2 className="heading-serif text-subsection text-charcoal">Messages</h2>
          <Link href="/messages" className="text-xs text-gold hover:text-goldLight transition-colors">View all</Link>
        </div>
        {threads.length === 0 ? (
          <div className="card-surface rounded-sm p-8 text-center">
            <p className="text-charcoal/40">No conversations yet</p>
          </div>
        ) : (
          <div className="space-y-3">
            {threads.slice(0, 3).map((t) => {
              const listing = store.getListing(t.listingId);
              const otherUserId = t.buyerId === session.user!.id ? t.sellerId : t.buyerId;
              const otherUser = store.findById(otherUserId);
              return (
                <Link key={t.id} href={`/messages/${t.id}`} className="card-surface card-surface-hover rounded-sm p-4 block transition-all duration-150">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-sm text-charcoal font-medium">
                        {otherUser?.name ?? 'Neighbor'} {listing ? `— ${listing.title}` : ''}
                      </p>
                    </div>
                    <span className="text-xs text-charcoal/30">
                      {new Date(t.lastMessageAt).toLocaleDateString()}
                    </span>
                  </div>
                </Link>
              );
            })}
          </div>
        )}
      </section>
    </main>
  );
}

import { NextResponse } from 'next/server';
import { store } from '@/lib/store';
import { auth } from '@/lib/auth';
import type { CategorySlug } from '@/lib/types';

export async function GET(req: Request) {
  const { searchParams } = new URL(req.url);
  const category = searchParams.get('category') as CategorySlug | null;
  const neighborhood = searchParams.get('neighborhood');
  const search = searchParams.get('search');

  let listings = store.listings.filter((l) => l.status === 'active' && !l.flagged);

  if (category) {
    listings = listings.filter((l) => l.category === category);
  }
  if (neighborhood) {
    listings = listings.filter((l) => l.neighborhood === neighborhood);
  }
  if (search) {
    const q = search.toLowerCase();
    listings = listings.filter(
      (l) =>
        l.title.toLowerCase().includes(q) ||
        l.description.toLowerCase().includes(q)
    );
  }

  return NextResponse.json(listings);
}

export async function POST(req: Request) {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const { title, description, price, category, neighborhood, photoUrl } = await req.json();

  if (!title || !description || !price || !category || !neighborhood) {
    return NextResponse.json({ error: 'All fields are required.' }, { status: 400 });
  }

  const listing = store.addListing({
    sellerId: session.user.id,
    title,
    description,
    price: Number(price),
    category,
    neighborhood,
    photoUrl: photoUrl || null,
  });

  return NextResponse.json(listing);
}

'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { signOut } from 'next-auth/react';

export default function NavbarClient({ session }: { session: any }) {
  const pathname = usePathname();
  const isActive = (path: string) =>
    pathname === path || pathname.startsWith(path + '/');

  return (
    <nav className="sticky top-0 z-50 bg-ivory/95 backdrop-blur border-b border-charcoal/5">
      <div className="max-w-6xl mx-auto px-6 h-16 flex items-center justify-between">
        <Link href="/" className="heading-serif text-xl text-charcoal">
          NearBy
        </Link>
        <div className="flex items-center gap-6 text-sm">
          <Link
            href="/browse"
            className={`transition-colors duration-150 ${isActive('/browse') ? 'text-gold font-medium' : 'text-charcoal/70 hover:text-charcoal'}`}
          >
            Browse
          </Link>
          <Link
            href="/sell"
            className={`transition-colors duration-150 ${isActive('/sell') ? 'text-gold font-medium' : 'text-charcoal/70 hover:text-charcoal'}`}
          >
            Sell
          </Link>
          {session ? (
            <>
              <Link
                href="/messages"
                className={`transition-colors duration-150 ${isActive('/messages') ? 'text-gold font-medium' : 'text-charcoal/70 hover:text-charcoal'}`}
              >
                Messages
              </Link>
              <Link
                href={`/profile/${session.user.id}`}
                className={`transition-colors duration-150 ${isActive('/profile') ? 'text-gold font-medium' : 'text-charcoal/70 hover:text-charcoal'}`}
              >
                {session.user.name?.split(' ')[0]}
              </Link>
              {session.user.role === 'admin' && (
                <Link
                  href="/admin"
                  className={`transition-colors duration-150 ${isActive('/admin') ? 'text-gold font-medium' : 'text-charcoal/70 hover:text-charcoal'}`}
                >
                  Admin
                </Link>
              )}
              <form action="/api/auth/signout" method="POST">
                <button type="submit" className="text-charcoal/50 hover:text-charcoal transition-colors duration-150">
                  Sign out
                </button>
              </form>
            </>
          ) : (
            <>
              <Link href="/login" className="text-charcoal/70 hover:text-charcoal transition-colors duration-150">
                Sign in
              </Link>
              <Link
                href="/signup"
                className="px-4 py-1.5 bg-gold text-white text-sm font-medium rounded-sm transition-colors duration-150 hover:bg-gold/90"
              >
                Join
              </Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
}

'use client';

import { SessionProvider } from 'next-auth/react';

export default function Providers({ children }: { children: React.ReactNode }) {
  return <SessionProvider>{children}</SessionProvider>;
}

/** @type {import('next').NextConfig} */
const nextConfig = {
  reactStrictMode: true,
};

module.exports = nextConfig;

