import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";
import Link from "next/link";
import { notFound } from "next/navigation";

export default async function ListingDetailPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) redirect(`/login?return=/dashboard/listings/${id}`);

  const { data: listing, error } = await supabase
    .from("listings")
    .select("*, profiles!inner(full_name, neighborhood, trust_score, is_verified, id)")
    .eq("id", id)
    .single();

  if (error || !listing) notFound();

  const isOwner = user.id === listing.user_id;

  const { data: reviewData } = await supabase
    .from("reviews")
    .select("rating")
    .eq("reviewed_id", listing.user_id);

  const avgRating = reviewData?.length
    ? (reviewData.reduce((sum, r) => sum + r.rating, 0) / reviewData.length).toFixed(1)
    : null;

  return (
    <div className="max-w-4xl mx-auto px-4 sm:px-6 py-8">
      {/* Breadcrumb */}
      <div className="font-mono text-xs text-white/30 mb-6">
        <Link href="/dashboard" className="hover:text-cyan transition-colors">Browse</Link>
        <span className="mx-2">/</span>
        <span className="text-white/50">{listing.title}</span>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Main content */}
        <div className="lg:col-span-2">
          {/* Image placeholder */}
          <div className="w-full h-64 sm:h-80 bg-ink-light rounded-xl mb-6 flex items-center justify-center border border-cyan/10">
            {listing.images?.[0] ? (
              <img src={listing.images[0]} alt={listing.title} className="w-full h-full object-cover rounded-xl" />
            ) : (
              <div className="text-center">
                <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" className="text-cyan/20 mx-auto mb-2" strokeWidth="1">
                  <rect x="3" y="3" width="18" height="18" rx="2" ry="2" />
                  <circle cx="8.5" cy="8.5" r="1.5" />
                  <polyline points="21 15 16 10 5 21" />
                </svg>
                <p className="font-mono text-xs text-white/20">No image</p>
              </div>
            )}
          </div>

          <div className="flex items-center gap-3 mb-4">
            <span className="px-3 py-1 bg-cyan/10 border border-cyan/20 rounded-full font-mono text-[10px] uppercase tracking-wider text-cyan">
              {listing.category}
            </span>
            <span className="px-3 py-1 bg-teal/10 border border-teal/20 rounded-full font-mono text-[10px] uppercase tracking-wider text-teal">
              {listing.condition}
            </span>
            {listing.status !== "active" && (
              <span className="px-3 py-1 bg-red-500/10 border border-red-500/20 rounded-full font-mono text-[10px] uppercase tracking-wider text-red-400">
                {listing.status}
              </span>
            )}
          </div>

          <h1 className="font-grotesk text-3xl font-semibold text-white mb-2">{listing.title}</h1>
          <p className="font-grotesk text-2xl font-bold text-teal mb-6">${Number(listing.price).toFixed(0)}</p>

          <div className="prose prose-invert max-w-none mb-8">
            <p className="text-white/60 font-grotesk leading-relaxed">{listing.description}</p>
          </div>

          {/* Action buttons */}
          {!isOwner && (
            <Link
              href={`/dashboard/messages/new?listing=${listing.id}&seller=${listing.user_id}`}
              className="inline-flex items-center gap-2 px-6 py-3 bg-cyan text-ink text-sm font-semibold font-grotesk rounded-md hover:bg-cyan/80 transition-colors"
            >
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
              </svg>
              Message Seller
            </Link>
          )}

          {isOwner && (
            <div className="flex gap-3">
              <Link
                href={`/dashboard/create?edit=${listing.id}`}
                className="px-6 py-3 bg-ink-light border border-cyan/20 text-cyan text-sm font-semibold font-grotesk rounded-md hover:bg-cyan/10 transition-colors"
              >
                Edit Listing
              </Link>
            </div>
          )}
        </div>

        {/* Sidebar */}
        <div className="lg:col-span-1">
          {/* Seller card */}
          <div className="bg-ink-light border border-cyan/10 rounded-xl p-5 mb-4">
            <h3 className="font-mono text-[10px] uppercase tracking-wider text-white/40 mb-3">Seller</h3>
            <div className="flex items-center gap-3 mb-4">
              <div className="w-10 h-10 rounded-full bg-gradient-to-br from-cyan to-teal flex items-center justify-center font-grotesk font-semibold text-ink text-sm">
                {listing.profiles.full_name?.[0]?.toUpperCase() || "?"}
              </div>
              <div>
                <p className="font-grotesk text-white font-medium">{listing.profiles.full_name}</p>
                <p className="font-mono text-[11px] text-white/30">{listing.profiles.neighborhood}</p>
              </div>
            </div>

            {/* Trust indicators */}
            <div className="space-y-2 mb-4">
              {listing.profiles.is_verified && (
                <div className="flex items-center gap-2 text-xs font-mono text-teal">
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z" />
                    <polyline points="9 12 11 14 15 10" />
                  </svg>
                  Verified Neighbor
                </div>
              )}
              <div className="flex items-center gap-2 text-xs font-mono text-cyan">
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                  <path d="M7 11V7a5 5 0 0110 0v4" />
                </svg>
                Government ID Verified
              </div>
              <div className="flex items-center gap-2 text-xs font-mono text-white/50">
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z" />
                  <circle cx="12" cy="10" r="3" />
                </svg>
                2-mile radius
              </div>
            </div>

            {/* Trust score */}
            <div className="border-t border-cyan/5 pt-4">
              <div className="flex items-center justify-between mb-1">
                <span className="font-mono text-[10px] uppercase tracking-wider text-white/30">Trust Score</span>
                <span className="font-mono text-sm font-bold text-teal">
                  {Number(listing.profiles.trust_score).toFixed(1)}
                </span>
              </div>
              <div className="w-full h-1.5 bg-ink rounded-full overflow-hidden">
                <div
                  className="h-full bg-gradient-to-r from-cyan to-teal rounded-full transition-all"
                  style={{ width: `${(Number(listing.profiles.trust_score) / 100) * 100}%` }}
                />
              </div>
            </div>
          </div>

          {/* Reviews summary */}
          <div className="bg-ink-light border border-cyan/10 rounded-xl p-5">
            <h3 className="font-mono text-[10px] uppercase tracking-wider text-white/40 mb-3">
              Reviews ({reviewData?.length || 0})
            </h3>
            {avgRating ? (
              <div className="flex items-center gap-2">
                <span className="font-grotesk text-2xl font-bold text-white">{avgRating}</span>
                <span className="font-mono text-xs text-white/30">/ 5.0</span>
                <div className="flex gap-0.5 ml-1">
                  {[1, 2, 3, 4, 5].map((star) => (
                    <svg key={star} width="14" height="14" viewBox="0 0 24 24" fill={star <= Math.round(Number(avgRating)) ? "#06b6d4" : "none"} stroke="#06b6d4" strokeWidth="1.5">
                      <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2" />
                    </svg>
                  ))}
                </div>
              </div>
            ) : (
              <p className="font-mono text-xs text-white/20">No reviews yet</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

