        }} />
        <div className="relative z-10 max-w-sm text-center">
          <Link href="/" className="font-grotesk text-4xl font-semibold text-white block mb-6">
            <span className="bg-gradient-to-r from-cyan to-teal bg-clip-text text-transparent">NearBy</span>
          </Link>
          <p className="text-white/40 font-mono text-sm leading-relaxed">
            Join your neighborhood marketplace. Verified, local, safe.
          </p>
        </div>
      </div>

      <div className="w-full lg:w-1/2 flex items-center justify-center p-8">
        <div className="w-full max-w-sm">
          <Link href="/" className="font-grotesk text-2xl font-semibold text-white block mb-8 lg:hidden">
