                value={fullName}
                onChange={(e) => setFullName(e.target.value)}
                className="w-full px-4 py-3 bg-ink-light border border-cyan/10 rounded-md text-white text-sm font-grotesk focus:border-teal focus:ring-1 focus:ring-teal/20 outline-none transition-colors placeholder:text-white/20"
