'use client';

import { useState, useEffect } from 'react';
import { useSearchParams } from 'next/navigation';
import Link from 'next/link';
import ItemCard from '@/components/ItemCard';
import { CATEGORIES, NEIGHBORHOODS } from '@/lib/store';
import type { Listing } from '@/lib/types';
import { Suspense } from 'react';

export default function BrowsePage() {
  return (
    <Suspense>
      <BrowseContent />
    </Suspense>
  );
}

function BrowseContent() {
  const searchParams = useSearchParams();
  const initialCategory = searchParams.get('category') || '';
  const initialNeighborhood = searchParams.get('neighborhood') || '';

  const [listings, setListings] = useState<Listing[]>([]);
  const [category, setCategory] = useState(initialCategory);
  const [neighborhood, setNeighborhood] = useState(initialNeighborhood);
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const params = new URLSearchParams();
    if (category) params.set('category', category);
    if (neighborhood) params.set('neighborhood', neighborhood);
    if (search) params.set('search', search);

    setLoading(true);
    fetch(`/api/listings?${params}`)
      .then((r) => r.json())
      .then((data) => {
        setListings(data);
        setLoading(false);
      });
  }, [category, neighborhood, search]);

  return (
    <main className="max-w-6xl mx-auto px-6 py-12">
      <div className="mb-8">
        <h1 className="heading-serif text-section-title text-charcoal mb-2">Browse</h1>
        <p className="text-charcoal/60">Find items from your neighbors</p>
      </div>

      {/* Filters */}
      <div className="flex flex-wrap gap-3 mb-8">
        <input
          type="text"
          placeholder="Search items..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="input-luxury rounded-sm px-4 py-2.5 text-sm flex-1 min-w-[200px]"
        />
        <select
          value={category}
          onChange={(e) => setCategory(e.target.value)}
          className="input-luxury rounded-sm px-4 py-2.5 text-sm"
        >
          <option value="">All categories</option>
          {CATEGORIES.map((c) => (
            <option key={c.slug} value={c.slug}>{c.name}</option>
          ))}
        </select>
        <select
          value={neighborhood}
          onChange={(e) => setNeighborhood(e.target.value)}
          className="input-luxury rounded-sm px-4 py-2.5 text-sm"
        >
          <option value="">All neighborhoods</option>
          {NEIGHBORHOODS.map((n) => (
            <option key={n} value={n}>{n}</option>
          ))}
        </select>
      </div>

      {/* Results */}
      {loading ? (
        <div className="text-center py-16 text-charcoal/40">Loading...</div>
      ) : listings.length === 0 ? (
        <div className="text-center py-16">
          <p className="text-charcoal/40 text-lg mb-4">No items found</p>
          <Link href="/sell" className="text-gold hover:text-goldLight transition-colors text-sm">
            Be the first to list something
          </Link>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {listings.map((listing) => (
            <ItemCard key={listing.id} listing={listing} />
          ))}
        </div>
      )}
    </main>
  );
}

import { auth } from '@/lib/auth';
import { redirect } from 'next/navigation';
import Link from 'next/link';
import { store } from '@/lib/store';

export default async function DashboardPage() {
  const session = await auth();
  if (!session?.user?.id) redirect('/login?return=/dashboard');

  const user = store.findById(session.user.id);
  const userListings = store.getUserListings(session.user.id);
  const activeListings = userListings.filter((l) => l.status === 'active');
  const soldListings = userListings.filter((l) => l.status === 'sold');
  const threads = store.getThreadsForUser(session.user.id);
  const reviews = store.getReviewsForUser(session.user.id);
  const trustScore = store.computeTrustScore(session.user.id);

  return (
    <main className="max-w-5xl mx-auto px-6 py-12">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="heading-serif text-section-title text-charcoal">Dashboard</h1>
          <p className="text-charcoal/50 mt-1">Welcome back, {user?.name ?? 'there'}</p>
        </div>
        <Link
          href="/sell"
          className="gold-gradient text-charcoal text-sm font-medium px-6 py-2.5 rounded-sm hover:opacity-90 transition-opacity"
        >
          + New listing
        </Link>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-12">
        {[
          { label: 'Active listings', value: activeListings.length },
          { label: 'Sold', value: soldListings.length },
          { label: 'Conversations', value: threads.length },
          { label: 'Trust score', value: `${trustScore}/5.0` },
        ].map((stat) => (
          <div key={stat.label} className="card-surface rounded-sm p-5 text-center">
            <p className="text-2xl font-heading text-charcoal">{stat.value}</p>
            <p className="text-xs text-charcoal/40 mt-1 uppercase tracking-wider">{stat.label}</p>
          </div>
        ))}
      </div>

      {/* Your listings */}
      <section className="mb-12">
        <div className="flex items-center justify-between mb-4">
          <h2 className="heading-serif text-subsection text-charcoal">Your listings</h2>
          <Link href="/browse" className="text-xs text-gold hover:text-goldLight transition-colors">Browse all</Link>
        </div>
        {activeListings.length === 0 ? (
          <div className="card-surface rounded-sm p-8 text-center">
            <p className="text-charcoal/40 mb-3">No active listings yet</p>
            <Link href="/sell" className="text-gold text-sm hover:text-goldLight transition-colors">List your first item</Link>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {activeListings.map((l) => (
              <Link key={l.id} href={`/items/${l.id}`} className="card-surface card-surface-hover rounded-sm p-4 block transition-all duration-150">
                <h3 className="font-heading text-charcoal leading-snug mb-1">{l.title}</h3>
                <p className="text-gold font-heading text-lg">${l.price}</p>
                <div className="flex items-center gap-2 text-xs text-charcoal/40 mt-2">
                  <span className="px-2 py-0.5 bg-ivoryDark rounded-sm capitalize">{l.category}</span>
                  <span>{l.neighborhood}</span>
                </div>
              </Link>
            ))}
          </div>
        )}
      </section>

      {/* Recent messages */}
      <section>
        <div className="flex items-center justify-between mb-4">
          <h2 className="heading-serif text-subsection text-charcoal">Messages</h2>
          <Link href="/messages" className="text-xs text-gold hover:text-goldLight transition-colors">View all</Link>
        </div>
        {threads.length === 0 ? (
          <div className="card-surface rounded-sm p-8 text-center">
            <p className="text-charcoal/40">No conversations yet</p>
          </div>
        ) : (
          <div className="space-y-3">
            {threads.slice(0, 3).map((t) => {
              const listing = store.getListing(t.listingId);
              const otherUserId = t.buyerId === session.user!.id ? t.sellerId : t.buyerId;
              const otherUser = store.findById(otherUserId);
              return (
                <Link key={t.id} href={`/messages/${t.id}`} className="card-surface card-surface-hover rounded-sm p-4 block transition-all duration-150">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-sm text-charcoal font-medium">
                        {otherUser?.name ?? 'Neighbor'} {listing ? `— ${listing.title}` : ''}
                      </p>
                    </div>
                    <span className="text-xs text-charcoal/30">
                      {new Date(t.lastMessageAt).toLocaleDateString()}
                    </span>
                  </div>
                </Link>
              );
            })}
          </div>
        )}
      </section>
    </main>
  );
}

import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";
import Link from "next/link";

const CATEGORIES = [
  "Baby Gear", "Toys", "Clothing", "Furniture", "Electronics", "Sports", "Books", "Other"
];

const CONDITIONS = ["New", "Like New", "Good", "Fair"];

export default async function DashboardPage({
  searchParams,
}: {
  searchParams: Promise<{ category?: string; search?: string; neighborhood?: string }>;
}) {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) redirect("/login?return=/dashboard");

  const params = await searchParams;
  const { category, search, neighborhood } = params;

  let query = supabase
    .from("listings")
    .select("*, profiles!inner(full_name, neighborhood, trust_score)")
    .eq("status", "active");

  if (category) query = query.eq("category", category);
  if (neighborhood) query = query.eq("neighborhood", neighborhood);
  if (search) query = query.or(`title.ilike.%${search}%,description.ilike.%${search}%`);

  query = query.order("created_at", { ascending: false });

  const { data: listings, error } = await query;

  // Get all neighborhoods for filter
  const { data: neighborhoods } = await supabase
    .from("listings")
    .select("neighborhood")
    .eq("status", "active");

  const uniqueNeighborhoods = [...new Set((neighborhoods || []).map((n) => n.neighborhood))];

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 py-8">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
        <div>
          <h1 className="font-grotesk text-3xl font-semibold text-white">Browse Listings</h1>
          <p className="font-mono text-sm text-white/40 mt-1">Find items from verified neighbors near you</p>
        </div>
        <Link
          href="/dashboard/create"
          className="inline-flex items-center gap-2 px-5 py-2.5 bg-cyan text-ink text-sm font-semibold font-grotesk rounded-md hover:bg-cyan/80 transition-colors self-start"
        >
          + New Listing
        </Link>
      </div>

      {/* Search and filters */}
      <div className="bg-ink-light border border-cyan/10 rounded-xl p-4 mb-8">
        <form className="flex flex-col sm:flex-row gap-3">
          <input
            type="text"
            name="search"
            defaultValue={search}
            placeholder="Search items..."
            className="flex-1 px-4 py-2.5 bg-ink border border-cyan/10 rounded-md text-white text-sm font-grotesk focus:border-cyan focus:ring-1 focus:ring-cyan/20 outline-none placeholder:text-white/20"
          />
          <select
            name="category"
            defaultValue={category || ""}
            className="px-4 py-2.5 bg-ink border border-cyan/10 rounded-md text-white/70 text-sm font-grotesk focus:border-cyan focus:ring-1 focus:ring-cyan/20 outline-none"
          >
            <option value="">All Categories</option>
            {CATEGORIES.map((c) => (
              <option key={c} value={c}>{c}</option>
            ))}
          </select>
          <select
            name="neighborhood"
            defaultValue={neighborhood || ""}
            className="px-4 py-2.5 bg-ink border border-cyan/10 rounded-md text-white/70 text-sm font-grotesk focus:border-cyan focus:ring-1 focus:ring-cyan/20 outline-none"
          >
            <option value="">All Neighborhoods</option>
            {uniqueNeighborhoods.map((n) => (
              <option key={n} value={n}>{n}</option>
            ))}
          </select>
          <button
            type="submit"
            className="px-6 py-2.5 bg-cyan/10 border border-cyan/20 text-cyan text-sm font-semibold font-grotesk rounded-md hover:bg-cyan/20 transition-colors"
          >
            Filter
          </button>
        </form>
      </div>

      {/* Listings grid */}
      {error && (
        <div className="text-red-400 font-mono text-sm mb-4">Error loading listings: {error.message}</div>
      )}

      {listings && listings.length === 0 && (
        <div className="text-center py-20">
          <p className="font-grotesk text-white/40 text-lg mb-2">No listings found</p>
          <p className="font-mono text-white/20 text-sm">Try adjusting your search or filters</p>
        </div>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {listings?.map((listing: any) => (
          <Link
            key={listing.id}
            href={`/dashboard/listings/${listing.id}`}
            className="group bg-ink-light border border-cyan/5 rounded-xl p-4 hover:border-cyan/20 transition-all duration-200 hover:-translate-y-0.5"
          >
            {/* Image placeholder */}
            <div className="w-full h-40 bg-ink rounded-lg mb-3 flex items-center justify-center border border-cyan/5">
              {listing.images?.[0] ? (
                <img src={listing.images[0]} alt="" className="w-full h-full object-cover rounded-lg" />
              ) : (
                <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" className="text-cyan/20" strokeWidth="1">
                  <rect x="3" y="3" width="18" height="18" rx="2" ry="2" />
                  <circle cx="8.5" cy="8.5" r="1.5" />
                  <polyline points="21 15 16 10 5 21" />
                </svg>
              )}
            </div>

            <div className="flex items-center justify-between mb-2">
              <span className="font-mono text-[10px] uppercase tracking-wider text-cyan/60">{listing.category}</span>
              <span className="font-mono text-[10px] text-white/30">{listing.condition}</span>
            </div>

            <h3 className="font-grotesk font-semibold text-white group-hover:text-cyan transition-colors leading-snug mb-1">
              {listing.title}
            </h3>

            <p className="font-grotesk text-lg font-bold text-teal mb-2">${Number(listing.price).toFixed(0)}</p>

            <div className="flex items-center gap-2 text-[11px] font-mono text-white/30">
              <span>{listing.neighborhood}</span>
              {listing.profiles?.trust_score != null && (
                <>
                  <span>·</span>
                  <span className="text-teal/60">
                    TS {Number(listing.profiles.trust_score).toFixed(1)}
                  </span>
                </>
              )}
            </div>
          </Link>
        ))}
      </div>
    </div>
