import { NextResponse } from 'next/server';
import { store } from '@/lib/store';
import { auth } from '@/lib/auth';

export async function GET(req: Request) {
  const { searchParams } = new URL(req.url);
  const userId = searchParams.get('userId');

  if (!userId) {
    return NextResponse.json({ error: 'userId is required.' }, { status: 400 });
  }

  const reviews = store.getReviewsForUser(userId).map((r) => {
    const reviewer = store.findById(r.reviewerId);
    return {
      ...r,
      reviewerName: reviewer?.name ?? 'Unknown',
    };
  });

  return NextResponse.json(reviews);
}

export async function POST(req: Request) {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const { revieweeId, listingId, rating, body } = await req.json();

  if (!revieweeId || !rating || !body?.trim()) {
    return NextResponse.json({ error: 'revieweeId, rating, and body are required.' }, { status: 400 });
  }

  if (revieweeId === session.user.id) {
    return NextResponse.json({ error: 'Cannot review yourself.' }, { status: 400 });
  }

  const review = store.addReview({
    reviewerId: session.user.id,
    revieweeId,
    listingId: listingId || undefined,
    rating: Number(rating) as 1 | 2 | 3 | 4 | 5,
    body: body.trim(),
  });

  return NextResponse.json(review);
}

import { NextResponse } from 'next/server';
import { store } from '@/lib/store';
import { auth } from '@/lib/auth';

export async function GET() {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const threads = store.getThreadsForUser(session.user.id);
  const enriched = threads.map((t) => {
    const listing = store.getListing(t.listingId);
    const otherUserId = t.buyerId === session.user!.id ? t.sellerId : t.buyerId;
    const otherUser = store.findById(otherUserId);
    const messages = store.getMessages(t.id);
    const lastMessage = messages[messages.length - 1];

    return {
      ...t,
      listing: listing ? { id: listing.id, title: listing.title, price: listing.price } : null,
      otherUser: otherUser ? { id: otherUser.id, name: otherUser.name } : null,
      lastMessage: lastMessage ? { body: lastMessage.body, senderId: lastMessage.senderId } : null,
      unread: lastMessage ? lastMessage.senderId !== session.user!.id : false,
    };
  });

  return NextResponse.json(enriched);
}

