import { NextResponse } from "next/server";
import { auth } from "@/lib/auth";
import { db } from "@/lib/db";
import { Category, Condition } from "@prisma/client";

export async function GET(req: Request) {
  const { searchParams } = new URL(req.url);
  const category = searchParams.get("category") as Category | null;
  const neighborhood = searchParams.get("neighborhood");
  const search = searchParams.get("search");
  const sort = searchParams.get("sort");

  const where: any = { status: "ACTIVE" };
  if (category && Object.keys(Category).includes(category)) {
    where.category = category;
  }
  if (neighborhood) {
    where.neighborhood = { contains: neighborhood, mode: "insensitive" };
  }
  if (search) {
    where.OR = [
      { title: { contains: search, mode: "insensitive" } },
      { description: { contains: search, mode: "insensitive" } },
    ];
  }

  const orderBy: any = sort === "price_asc"
    ? { price: "asc" }
    : sort === "price_desc"
    ? { price: "desc" }
    : { createdAt: "desc" };

  const listings = await db.listing.findMany({
    where,
    orderBy,
    include: {
      seller: { select: { id: true, name: true, trustScore: true, neighborhood: true } },
    },
  });

  return NextResponse.json(listings);
}

export async function POST(req: Request) {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { title, description, price, category, condition, neighborhood, imageUrl, imageUrls } = await req.json();

  if (!title || !description || !price || !category) {
    return NextResponse.json({ error: "Missing required fields." }, { status: 400 });
  }

  const listing = await db.listing.create({
    data: {
      title,
      description,
      price: Number(price),
      category: category as Category,
      condition: (condition as Condition) || "GOOD",
      neighborhood: neighborhood || "",
      imageUrl: imageUrl || null,
      imageUrls: imageUrls || [],
      sellerId: session.user.id,
    },
  });

  return NextResponse.json(listing, { status: 201 });
}

import { NextResponse } from "next/server";
import { auth } from "@/lib/auth";
import { db } from "@/lib/db";

export async function GET(req: Request, { params }: { params: Promise<{ id: string }> }) {
  const { id } = await params;

  const listing = await db.listing.findUnique({
    where: { id },
    include: { seller: true },
  });

  if (!listing) return NextResponse.json({ error: "Not found" }, { status: 404 });

  return NextResponse.json(listing);
}

export async function PUT(req: Request, { params }: { params: Promise<{ id: string }> }) {
  const session = await auth();
  if (!session?.user?.id) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const { id } = await params;
  const listing = await db.listing.findUnique({ where: { id } });

  if (!listing) return NextResponse.json({ error: "Not found" }, { status: 404 });
  if (listing.sellerId !== session.user.id) return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  const body = await req.json();
  const updated = await db.listing.update({ where: { id }, data: body });

  return NextResponse.json(updated);
}

export async function DELETE(req: Request, { params }: { params: Promise<{ id: string }> }) {
  const session = await auth();
  if (!session?.user?.id) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const { id } = await params;
  const listing = await db.listing.findUnique({ where: { id } });

  if (!listing) return NextResponse.json({ error: "Not found" }, { status: 404 });
  if (listing.sellerId !== session.user.id) return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  await db.listing.update({ where: { id }, data: { status: "REMOVED" } });

  return NextResponse.json({ ok: true });
}

