import Link from "next/link";
import { formatDistanceToNow } from "date-fns";

interface ListingCardProps {
  listing: {
    id: string;
    title: string;
    price: any;
    category: string;
    condition: string;
    neighborhood: string;
    imageUrl?: string | null;
    createdAt: Date;
    seller: { id: string; name: string; trustScore: number; neighborhood: string };
  };
}

export default function ListingCard({ listing }: ListingCardProps) {
  return (
    <Link
      href={`/listings/${listing.id}`}
      className="group bg-white rounded-xl border border-product-charcoal/5 hover:border-violet/20 hover:shadow-sm transition-all duration-200 hover:-translate-y-0.5 overflow-hidden"
    >
      <div className="w-full aspect-square bg-gradient-to-br from-violet/5 to-honey/5 flex items-center justify-center">
        {listing.imageUrl ? (
          <img src={listing.imageUrl} alt={listing.title} className="w-full h-full object-cover" />
        ) : (
          <span className="text-3xl font-bold text-violet/15 font-manrope">{listing.title[0]}</span>
        )}
      </div>
      <div className="p-4">
        <div className="flex items-center justify-between mb-2">
          <span className="text-[10px] font-semibold uppercase tracking-wider text-violet/60 font-manrope">
            {listing.category.replace("_", " ")}
          </span>
          <span className="text-[10px] text-product-charcoal/30 font-source-sans">
            {listing.condition.replace("_", " ")}
          </span>
        </div>
        <h3 className="font-manrope font-semibold text-sm text-product-charcoal group-hover:text-violet transition-colors leading-snug mb-1 line-clamp-2">
          {listing.title}
        </h3>
        <p className="text-lg font-bold text-violet font-manrope mb-2">${Number(listing.price).toFixed(0)}</p>
        <div className="flex items-center gap-2 text-[11px] text-product-charcoal/35 font-source-sans">
          <span>{listing.neighborhood}</span>
          <span>·</span>
          <span className="flex items-center gap-1">
            <svg width="10" height="10" viewBox="0 0 24 24" fill="#F59E0B"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
            {listing.seller.trustScore / 10}
          </span>
          <span>·</span>
          <span>{formatDistanceToNow(listing.createdAt, { addSuffix: true })}</span>
        </div>
      </div>
    </Link>
  );
}

"use client";

import { useRouter, useSearchParams } from "next/navigation";
import { useCallback, useState } from "react";

const CATEGORIES = [
  { value: "", label: "All Categories" },
  { value: "ELECTRONICS", label: "Electronics" },
  { value: "FURNITURE", label: "Furniture" },
  { value: "CLOTHING", label: "Clothing" },
  { value: "BABY_GEAR", label: "Baby Gear" },
  { value: "SPORTS", label: "Sports" },
  { value: "BOOKS", label: "Books" },
  { value: "HOME_GARDEN", label: "Home & Garden" },
  { value: "TOYS", label: "Toys" },
  { value: "VEHICLES", label: "Vehicles" },
  { value: "OTHER", label: "Other" },
];

const SORT_OPTIONS = [
  { value: "", label: "Newest" },
  { value: "price_asc", label: "Price: Low to High" },
  { value: "price_desc", label: "Price: High to Low" },
];

interface FilterBarProps {
  initialCategory?: string;
  initialSearch?: string;
  initialNeighborhood?: string;
  initialSort?: string;
  neighborhoods: string[];
}

export default function FilterBar({ initialCategory, initialSearch, initialNeighborhood, initialSort, neighborhoods }: FilterBarProps) {
  const router = useRouter();
  const searchParams = useSearchParams();

  const [category, setCategory] = useState(initialCategory || "");
  const [search, setSearch] = useState(initialSearch || "");
  const [neighborhood, setNeighborhood] = useState(initialNeighborhood || "");
  const [sort, setSort] = useState(initialSort || "");

  const applyFilters = useCallback(() => {
    const params = new URLSearchParams();
    if (search) params.set("search", search);
    if (category) params.set("category", category);
    if (neighborhood) params.set("neighborhood", neighborhood);
    if (sort) params.set("sort", sort);
    const qs = params.toString();
    router.push(qs ? `?${qs}` : "");
  }, [search, category, neighborhood, sort, router]);

  return (
    <div className="bg-white rounded-xl p-4 mb-6 border border-product-charcoal/5 shadow-sm">
      <div className="flex flex-wrap gap-3">
        <input
          type="text"
          placeholder="Search items..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && applyFilters()}
          className="flex-1 min-w-[180px] px-4 py-2.5 bg-warm-white border border-product-charcoal/10 rounded-xl text-sm font-source-sans focus:border-violet focus:ring-2 focus:ring-violet/10 outline-none transition-all placeholder:text-product-charcoal/25"
        />
        <select
          value={category}
          onChange={(e) => { setCategory(e.target.value); }}
          className="px-4 py-2.5 bg-warm-white border border-product-charcoal/10 rounded-xl text-sm font-source-sans text-product-charcoal/70 focus:border-violet focus:ring-2 focus:ring-violet/10 outline-none"
        >
          {CATEGORIES.map((c) => (
            <option key={c.value} value={c.value}>{c.label}</option>
          ))}
        </select>
        {neighborhoods.length > 0 && (
          <select
            value={neighborhood}
            onChange={(e) => setNeighborhood(e.target.value)}
            className="px-4 py-2.5 bg-warm-white border border-product-charcoal/10 rounded-xl text-sm font-source-sans text-product-charcoal/70 focus:border-violet focus:ring-2 focus:ring-violet/10 outline-none"
          >
            <option value="">All Neighborhoods</option>
            {neighborhoods.map((n) => (
              <option key={n} value={n}>{n}</option>
            ))}
          </select>
        )}
        <select
          value={sort}
          onChange={(e) => setSort(e.target.value)}
          className="px-4 py-2.5 bg-warm-white border border-product-charcoal/10 rounded-xl text-sm font-source-sans text-product-charcoal/70 focus:border-violet focus:ring-2 focus:ring-violet/10 outline-none"
        >
          {SORT_OPTIONS.map((s) => (
            <option key={s.value} value={s.value}>{s.label}</option>
          ))}
        </select>
        <button
          onClick={applyFilters}
          className="px-5 py-2.5 bg-violet text-white text-sm font-semibold font-manrope rounded-xl hover:bg-violet/90 transition-colors"
        >
          Apply
        </button>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";

const CATEGORIES = [
  { value: "ELECTRONICS", label: "Electronics" },
  { value: "FURNITURE", label: "Furniture" },
  { value: "CLOTHING", label: "Clothing" },
  { value: "BABY_GEAR", label: "Baby Gear" },
  { value: "SPORTS", label: "Sports" },
  { value: "BOOKS", label: "Books" },
  { value: "HOME_GARDEN", label: "Home & Garden" },
  { value: "TOYS", label: "Toys" },
  { value: "VEHICLES", label: "Vehicles" },
  { value: "OTHER", label: "Other" },
];

const CONDITIONS = ["NEW", "LIKE_NEW", "GOOD", "FAIR"];

export default function CreateListingForm() {
  const router = useRouter();
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [price, setPrice] = useState("");
  const [category, setCategory] = useState("ELECTRONICS");
  const [condition, setCondition] = useState("GOOD");
  const [neighborhood, setNeighborhood] = useState("");
  const [imageUrl, setImageUrl] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError("");
    setLoading(true);

    const res = await fetch("/api/listings", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        title,
        description,
        price: Number(price),
        category,
        condition,
        neighborhood,
        imageUrl: imageUrl || null,
        imageUrls: imageUrl ? [imageUrl] : [],
      }),
    });

    setLoading(false);

    if (!res.ok) {
      const data = await res.json();
      setError(data.error || "Failed to create listing.");
      return;
    }

    const listing = await res.json();
    router.push(`/listings/${listing.id}`);
  }

  return (
    <form onSubmit={handleSubmit} className="bg-white rounded-2xl p-6 sm:p-8 border border-product-charcoal/5 shadow-sm space-y-5">
      {error && (
        <div className="px-4 py-3 bg-coral/10 border border-coral/20 text-coral text-sm rounded-xl font-source-sans">{error}</div>
      )}

      <div>
        <label className="block text-sm font-medium text-product-charcoal mb-1.5 font-manrope">Title *</label>
        <input type="text" required value={title} onChange={(e) => setTitle(e.target.value)}
          className="w-full px-4 py-3 bg-warm-white border border-product-charcoal/10 rounded-xl text-product-charcoal text-sm font-source-sans focus:border-violet focus:ring-2 focus:ring-violet/10 outline-none transition-all"
          placeholder="e.g. Vintage denim jacket" />
      </div>

      <div>
        <label className="block text-sm font-medium text-product-charcoal mb-1.5 font-manrope">Description *</label>
        <textarea required value={description} onChange={(e) => setDescription(e.target.value)} rows={4}
          className="w-full px-4 py-3 bg-warm-white border border-product-charcoal/10 rounded-xl text-product-charcoal text-sm font-source-sans focus:border-violet focus:ring-2 focus:ring-violet/10 outline-none transition-all resize-none"
          placeholder="Describe your item — condition, brand, size, any notes..." />
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-medium text-product-charcoal mb-1.5 font-manrope">Price ($) *</label>
          <input type="number" required min="1" step="0.01" value={price} onChange={(e) => setPrice(e.target.value)}
            className="w-full px-4 py-3 bg-warm-white border border-product-charcoal/10 rounded-xl text-product-charcoal text-sm font-source-sans focus:border-violet focus:ring-2 focus:ring-violet/10 outline-none transition-all"
            placeholder="0.00" />
        </div>
        <div>
          <label className="block text-sm font-medium text-product-charcoal mb-1.5 font-manrope">Category *</label>
          <select value={category} onChange={(e) => setCategory(e.target.value)}
            className="w-full px-4 py-3 bg-warm-white border border-product-charcoal/10 rounded-xl text-product-charcoal text-sm font-source-sans focus:border-violet focus:ring-2 focus:ring-violet/10 outline-none transition-all">
            {CATEGORIES.map((c) => <option key={c.value} value={c.value}>{c.label}</option>)}
          </select>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-medium text-product-charcoal mb-1.5 font-manrope">Condition</label>
          <select value={condition} onChange={(e) => setCondition(e.target.value)}
            className="w-full px-4 py-3 bg-warm-white border border-product-charcoal/10 rounded-xl text-product-charcoal text-sm font-source-sans focus:border-violet focus:ring-2 focus:ring-violet/10 outline-none transition-all">
            {CONDITIONS.map((c) => <option key={c} value={c}>{c.replace("_", " ")}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-sm font-medium text-product-charcoal mb-1.5 font-manrope">Neighborhood</label>
          <input type="text" value={neighborhood} onChange={(e) => setNeighborhood(e.target.value)}
            className="w-full px-4 py-3 bg-warm-white border border-product-charcoal/10 rounded-xl text-product-charcoal text-sm font-source-sans focus:border-violet focus:ring-2 focus:ring-violet/10 outline-none transition-all"
            placeholder="e.g. Williamsburg" />
        </div>
      </div>

      <div>
        <label className="block text-sm font-medium text-product-charcoal mb-1.5 font-manrope">Image URL</label>
        <input type="url" value={imageUrl} onChange={(e) => setImageUrl(e.target.value)}
          className="w-full px-4 py-3 bg-warm-white border border-product-charcoal/10 rounded-xl text-product-charcoal text-sm font-source-sans focus:border-violet focus:ring-2 focus:ring-violet/10 outline-none transition-all"
          placeholder="https://example.com/photo.jpg" />
      </div>

      <button type="submit" disabled={loading}
        className="w-full py-3 bg-violet text-white text-sm font-semibold font-manrope rounded-xl hover:bg-violet/90 transition-colors disabled:opacity-50">
        {loading ? "Creating listing..." : "Create Listing"}
      </button>
    </form>
  );
}

