"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import StarRating from "./StarRating";

interface WriteReviewFormProps {
  reviewedId: string;
  listingId?: string;
}

export default function WriteReviewForm({ reviewedId, listingId }: WriteReviewFormProps) {
  const router = useRouter();
  const [rating, setRating] = useState(5);
  const [comment, setComment] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError("");
    setLoading(true);

    const res = await fetch("/api/reviews", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ reviewedId, listingId: listingId || null, rating, comment }),
    });

    setLoading(false);

    if (!res.ok) {
      const data = await res.json();
      setError(data.error || "Failed to submit review.");
      return;
    }

    setComment("");
    setShowForm(false);
    router.refresh();
  }

  if (!showForm) {
    return (
      <button
        onClick={() => setShowForm(true)}
        className="text-sm text-violet font-medium font-manrope hover:text-violet/80 transition-colors"
      >
        Write a review
      </button>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-3">
      {error && <p className="text-xs text-coral font-source-sans">{error}</p>}
      <div>
        <label className="block text-xs font-medium text-product-charcoal/60 mb-1.5 font-manrope">Rating</label>
        <StarRating rating={rating} onChange={setRating} size="md" />
      </div>
      <div>
