import { NextResponse } from 'next/server';
import { store } from '@/lib/store';
import { auth } from '@/lib/auth';

export async function GET(
  req: Request,
  { params }: { params: { threadId: string } }
) {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const thread = store.getThread(params.threadId);
  if (!thread) {
    return NextResponse.json({ error: 'Thread not found' }, { status: 404 });
  }

  if (thread.buyerId !== session.user.id && thread.sellerId !== session.user.id) {
    return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
  }

  const messages = store.getMessages(params.threadId);
  const listing = store.getListing(thread.listingId);
  const otherUserId = thread.buyerId === session.user.id ? thread.sellerId : thread.buyerId;
  const otherUser = store.findById(otherUserId);

  return NextResponse.json({
    thread,
    messages,
    listing: listing ? { id: listing.id, title: listing.title, price: listing.price, sellerId: listing.sellerId } : null,
    otherUser: otherUser ? { id: otherUser.id, name: otherUser.name } : null,
  });
}

export async function POST(
  req: Request,
  { params }: { params: { threadId: string } }
) {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const thread = store.getThread(params.threadId);
  if (!thread) {
    return NextResponse.json({ error: 'Thread not found' }, { status: 404 });
  }

  if (thread.buyerId !== session.user.id && thread.sellerId !== session.user.id) {
    return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
  }

  const { body } = await req.json();
  if (!body?.trim()) {
    return NextResponse.json({ error: 'Message body is required.' }, { status: 400 });
  }

  const msg = store.addMessage(params.threadId, session.user.id, body.trim());
  return NextResponse.json(msg);
}

