import LandingNavbar from "@/components/LandingNavbar";
import LandingHero from "@/components/LandingHero";
import TrustFeatures from "@/components/TrustFeatures";
import LandingHowItWorks from "@/components/LandingHowItWorks";
import Benefits from "@/components/Benefits";
import Testimonials from "@/components/Testimonials";
import CTA from "@/components/CTA";
import LandingWaitlist from "@/components/LandingWaitlist";
import LandingFAQ from "@/components/LandingFAQ";
import LandingFooter from "@/components/LandingFooter";

export default function Home() {
  return (
    <div className="min-h-screen bg-[#030712]">
      <LandingNavbar />
      <LandingHero />
      <TrustFeatures />
      <LandingHowItWorks />
      <Benefits />
      <Testimonials />
      <CTA />
      <LandingWaitlist />
      <LandingFAQ />
      <LandingFooter />
    </div>
  );
}

'use client';

export default function LandingNavbar() {
  return (
    <nav className="sticky top-0 z-50 bg-[#030712]/90 backdrop-blur-md border-b border-[#1F2937]">
      <div className="max-w-6xl mx-auto px-6 h-16 flex items-center justify-between">
        <a href="#" className="text-xl font-bold tracking-tight bg-gradient-to-r from-[#00C8A0] to-[#EC4899] bg-clip-text text-transparent" style={{ fontFamily: "'Space Grotesk', sans-serif" }}>
          NearBy
        </a>
        <a
          href="#waitlist"
          className="px-4 py-2 rounded-full border border-[#00C8A0]/30 text-[#00C8A0] text-sm font-medium hover:bg-[#00C8A0]/10 transition-all duration-200"
          style={{ fontFamily: "'DM Sans', sans-serif" }}
        >
          Join Waitlist
        </a>
      </div>
    </nav>
  );
}

const steps = [
  {
    number: "01",
    title: "Verify Your Identity",
    description:
      "Upload your government-issued ID and proof of address. We verify who you are, confirm your neighborhood, and issue your trust badge.",
    icon: (
      <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
        <rect x="2" y="5" width="20" height="14" rx="2" />
        <line x1="2" y1="10" x2="22" y2="10" />
        <circle cx="8" cy="17" r="1" fill="currentColor" />
      </svg>
    ),
  },
  {
    number: "02",
    title: "Browse Items from Neighbors",
    description:
      "Scroll through items your neighbors are selling — baby gear, furniture, electronics — all within a 2-mile radius of your verified address.",
    icon: (
      <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
        <rect x="2" y="7" width="20" height="13" rx="2" />
        <circle cx="8" cy="12" r="2" />
        <path d="M2 17l5-5 3 3 4-4 5 5" />
      </svg>
    ),
  },
  {
    number: "03",
    title: "Meet Safely & Transact",
    description:
      "Chat in-app, agree on a meeting spot (the café, the park), and exchange items. No phone numbers shared — just trusted, local transactions.",
    icon: (
      <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
        <path d="M22 12h-4l-3 9L9 3l-3 9H2" />
      </svg>
    ),
  },
];

export default function LandingHowItWorks() {
  return (
    <section className="py-24 px-6 bg-[#111827]">
      <div className="max-w-5xl mx-auto">
        <div className="text-center mb-16">
          <span
            className="text-[11px] font-semibold tracking-[0.2em] uppercase text-[#00C8A0] mb-4 block"
            style={{ fontFamily: "'Space Grotesk', sans-serif" }}
          >
            How It Works
          </span>
          <h2
            className="text-3xl md:text-4xl font-bold text-[#F9FAFB] text-balance"
            style={{ fontFamily: "'Space Grotesk', sans-serif" }}
          >
            Three Steps to Safer Local Commerce
          </h2>
          <div className="w-12 h-[2px] bg-[#00C8A0]/40 mx-auto mt-6" />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 md:gap-10">
          {steps.map((step, i) => (
            <div key={step.number} className="relative text-center px-4">
              {i < steps.length - 1 && (
                <div className="hidden md:block absolute top-16 left-[calc(50%+32px)] right-[calc(-50%+32px)] h-[1px] bg-[#00C8A0]/15" />
              )}

              <div className="relative inline-flex items-center justify-center w-16 h-16 rounded-full border border-[#00C8A0]/20 bg-[#030712] mb-6">
                <span
                  className="text-lg font-bold text-[#00C8A0]"
                  style={{ fontFamily: "'Space Grotesk', sans-serif" }}
                >
                  {step.number}
                </span>
              </div>

              <div className="text-[#00C8A0]/70 mb-4 flex justify-center">
                {step.icon}
              </div>

              <h3
                className="text-xl font-semibold text-[#F9FAFB] mb-3"
                style={{ fontFamily: "'Space Grotesk', sans-serif" }}
              >
                {step.title}
              </h3>
              <p
                className="text-sm leading-relaxed text-[#9CA3AF] max-w-xs mx-auto"
                style={{ fontFamily: "'DM Sans', sans-serif" }}
              >
                {step.description}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

'use client';

import { useState, FormEvent } from 'react';

export default function LandingWaitlist() {
  const [email, setEmail] = useState('');
  const [status, setStatus] = useState<'idle' | 'submitting' | 'success' | 'error'>('idle');
  const [errorMsg, setErrorMsg] = useState('');

  async function handleSubmit(e: FormEvent) {
    e.preventDefault();
    if (!email) return;

    setStatus('submitting');
    setErrorMsg('');

    try {
      const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
      const supabaseKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;

      if (!supabaseUrl || !supabaseKey || supabaseUrl.includes('placeholder')) {
        const existing = JSON.parse(localStorage.getItem('nearby_waitlist') || '[]');
        if (!existing.includes(email)) {
          existing.push(email);
          localStorage.setItem('nearby_waitlist', JSON.stringify(existing));
        }
        setStatus('success');
        setEmail('');
        return;
      }

      const res = await fetch(`${supabaseUrl}/rest/v1/waitlist`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          apikey: supabaseKey,
          Authorization: `Bearer ${supabaseKey}`,
          Prefer: 'return=representation',
        },
        body: JSON.stringify({ email }),
      });

      if (res.ok) {
        setStatus('success');
        setEmail('');
      } else {
        const data = await res.json();
        if (data.code === '23505') {
          setStatus('success');
          setEmail('');
        } else {
          setErrorMsg(data.message || 'Something went wrong. Please try again.');
          setStatus('error');
        }
      }
    } catch {
      setErrorMsg('Network error. Please try again.');
      setStatus('error');
    }
  }

  return (
    <section id="waitlist" className="py-24 px-6 bg-[#111827] relative overflow-hidden">
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[500px] h-[500px] rounded-full bg-[#00C8A0]/5 blur-[100px]" />

      <div className="relative z-10 max-w-2xl mx-auto text-center">
        <span
          className="text-[11px] font-semibold tracking-[0.2em] uppercase text-[#00C8A0] mb-4 block"
          style={{ fontFamily: "'Space Grotesk', sans-serif" }}
        >
          Get Early Access
        </span>
        <h2
          className="text-3xl md:text-4xl font-bold text-[#F9FAFB] text-balance mb-4"
          style={{ fontFamily: "'Space Grotesk', sans-serif" }}
        >
          Be First in Your Neighborhood
        </h2>
        <p
          className="text-sm leading-relaxed text-[#9CA3AF] mb-10 max-w-md mx-auto"
          style={{ fontFamily: "'DM Sans', sans-serif" }}
        >
          Join the waitlist and we'll notify you the moment NearBy launches in
          your area. Early members get priority access and help shape the platform.
        </p>

        {status === 'success' ? (
          <div className="p-8 rounded-2xl bg-[#030712] border border-[#00C8A0]/20">
            <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-[#00C8A0]/10 mb-4">
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#00C8A0" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <polyline points="20 6 9 17 4 12" />
              </svg>
            </div>
            <h3
              className="text-xl font-semibold text-[#F9FAFB] mb-2"
              style={{ fontFamily: "'Space Grotesk', sans-serif" }}
            >
              You're on the list
            </h3>
            <p
              className="text-sm text-[#9CA3AF]"
              style={{ fontFamily: "'DM Sans', sans-serif" }}
            >
              We'll notify you as soon as NearBy is ready. Keep an eye on your inbox.
            </p>
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="flex flex-col sm:flex-row gap-3 max-w-lg mx-auto">
            <input
              type="email"
              required
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="your@email.com"
              className="flex-1 px-5 py-3.5 rounded-full bg-[#1F2937] border border-white/10 text-[#F9FAFB] text-sm placeholder:text-[#9CA3AF] focus:outline-none focus:border-[#00C8A0]/40 focus:ring-1 focus:ring-[#00C8A0]/20 transition-all"
              disabled={status === 'submitting'}
              style={{ fontFamily: "'DM Sans', sans-serif" }}
            />
            <button
              type="submit"
              disabled={status === 'submitting'}
              className="px-7 py-3.5 rounded-full bg-[#00C8A0] text-[#030712] text-sm font-semibold tracking-wide transition-all duration-300 hover:shadow-lg hover:shadow-[#00C8A0]/20 hover:-translate-y-0.5 disabled:opacity-60 disabled:cursor-not-allowed whitespace-nowrap"
              style={{ fontFamily: "'DM Sans', sans-serif" }}
            >
              {status === 'submitting' ? (
                <span className="inline-flex items-center gap-2">
                  <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
                  </svg>
                  Joining...
                </span>
              ) : (
                'Join the Waitlist'
              )}
            </button>
          </form>
        )}

        {status === 'error' && errorMsg && (
          <p
            className="mt-4 text-sm text-red-400"
            style={{ fontFamily: "'DM Sans', sans-serif" }}
          >
            {errorMsg}
          </p>
        )}

        <p
          className="mt-6 text-[11px] text-[#9CA3AF]/50"
          style={{ fontFamily: "'DM Sans', sans-serif" }}
        >
          No spam — just a single email when we launch in your neighborhood.
        </p>
      </div>
    </section>
  );
}

'use client';

import { useState } from 'react';

const faqs = [
  {
    question: 'How is NearBy different from Facebook Marketplace?',
    answer:
      'Facebook Marketplace connects you with strangers — often anonymous accounts with no verification. NearBy requires government ID verification, limits transactions to a 2-mile radius, and ensures you\'re dealing with verified neighbors who have a real stake in your community.',
  },
  {
    question: 'What kind of items can I sell?',
    answer:
      'Baby gear, furniture, electronics, household items, clothing, sports equipment, and more — as long as it\'s legal and local. We focus on the items neighbors actually need and use every day.',
  },
  {
    question: 'Is there a fee?',
    answer:
      'NearBy charges a small buyer-side service fee (5%) to keep the platform safe, verified, and spam-free. Listing items is free. No hidden costs, no subscription — just a transparent fee that funds trust and verification.',
  },
  {
    question: 'When will NearBy launch in my neighborhood?',
    answer:
      'We\'re launching in select neighborhoods soon and rolling out based on demand. Join the waitlist and we\'ll notify you the moment your area goes live. The more neighbors from your area who sign up, the sooner you get access.',
  },
  {
    question: 'How does the ID verification work?',
    answer:
      'You upload a government-issued ID plus proof of address. We verify your identity, confirm you reside within your stated neighborhood, and issue a Neighborhood Badge. Your personal information is never shared with other users — we only confirm that you\'re a verified resident.',
  },
];

export default function LandingFAQ() {
  const [openIndex, setOpenIndex] = useState<number | null>(null);

  return (
    <section className="py-24 px-6 bg-[#030712]">
      <div className="max-w-2xl mx-auto">
        <div className="text-center mb-14">
          <span
            className="text-[11px] font-semibold tracking-[0.2em] uppercase text-[#F2A900] mb-4 block"
            style={{ fontFamily: "'Space Grotesk', sans-serif" }}
          >
            FAQ
          </span>
          <h2
            className="text-3xl md:text-4xl font-bold text-[#F9FAFB]"
            style={{ fontFamily: "'Space Grotesk', sans-serif" }}
          >
            Honest Answers
          </h2>
          <div className="w-12 h-[2px] bg-[#F2A900]/40 mx-auto mt-6" />
        </div>

        <div className="space-y-0">
          {faqs.map((faq, index) => (
            <div key={index} className="border-b border-[#1F2937] last:border-b-0">
              <button
                onClick={() => setOpenIndex(openIndex === index ? null : index)}
                className="w-full flex items-center justify-between py-5 text-left group"
                aria-expanded={openIndex === index}
              >
                <span
                  className="text-base md:text-lg font-semibold text-[#F9FAFB] group-hover:text-[#00C8A0] transition-colors duration-200 pr-4"
                  style={{ fontFamily: "'Space Grotesk', sans-serif" }}
                >
                  {faq.question}
                </span>
                <span className="flex-shrink-0 w-8 h-8 rounded-full border border-[#1F2937] flex items-center justify-center group-hover:border-[#00C8A0]/30 transition-colors">
                  <svg
                    width="14"
                    height="14"
                    viewBox="0 0 14 14"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="1.5"
                    strokeLinecap="round"
                    className={`text-[#9CA3AF] transition-transform duration-300 ${
                      openIndex === index ? 'rotate-45' : ''
                    }`}
                  >
                    <line x1="7" y1="1" x2="7" y2="13" />
                    <line x1="1" y1="7" x2="13" y2="7" />
                  </svg>
                </span>
              </button>
              <div
                className={`overflow-hidden transition-all duration-400 ease-in-out ${
                  openIndex === index ? 'max-h-96 pb-5' : 'max-h-0'
                }`}
              >
                <p
                  className="text-sm leading-relaxed text-[#9CA3AF] pr-12"
                  style={{ fontFamily: "'DM Sans', sans-serif" }}
                >
                  {faq.answer}
                </p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

